export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronExpression, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function rangeArray(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function clampValues(values: number[], min: number, max: number): number[] {
  const filtered = [...new Set(values)].filter(v => v >= min && v <= max).sort((a, b) => a - b);
  if (filtered.length === 0) throw new RangeError(`No valid values in range [${min}, ${max}]`);
  return filtered;
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap(part => parseField(part.trim(), min, max));
    return clampValues(values, min, max);
  }

  // Wildcard
  if (field === "*") return rangeArray(min, max);

  // Step value: */n or range/n
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new SyntaxError(`Invalid step value: "${stepStr}"`);

    const [rangeMin, rangeMax] =
      rangePart === "*" ? [min, max] : parseRange(rangePart, min, max);

    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) values.push(v);
    return clampValues(values, min, max);
  }

  // Range: a-b
  if (field.includes("-")) {
    const [rangeMin, rangeMax] = parseRange(field, min, max);
    return clampValues(rangeArray(rangeMin, rangeMax), min, max);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid cron field value: "${field}"`);
  return clampValues([value], min, max);
}

function parseRange(part: string, min: number, max: number): [number, number] {
  const [startStr, endStr] = part.split("-");
  const start = parseInt(startStr, 10);
  const end = parseInt(endStr, 10);
  if (isNaN(start) || isNaN(end)) throw new SyntaxError(`Invalid range: "${part}"`);
  if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end}`);
  if (start < min || end > max) throw new RangeError(`Range "${part}" out of bounds [${min}, ${max}]`);
  return [start, end];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 cron fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;
  const [minRange, hourRange, domRange, monthRange, dowRange] = Object.values(FIELD_RANGES);

  return {
    minute: parseField(minuteStr, ...minRange),
    hour: parseField(hourStr, ...hourRange),
    dayOfMonth: parseField(domStr, ...domRange),
    month: parseField(monthStr, ...monthRange),
    dayOfWeek: parseField(dowStr, ...dowRange),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const range = (from: number, to: number): number[] =>
  Array.from({ length: to - from + 1 }, (_, i) => from + i);

const parseField = (field: string, min: number, max: number): number[] => {
  const allValues = range(min, max);

  // Wildcard
  if (field === "*") return allValues;

  // Step with wildcard: */n
  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    return allValues.filter((v) => (v - min) % step === 0);
  }

  // Comma-separated list
  if (field.includes(",")) {
    const values = field
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Range with optional step: n-m or n-m/s
  if (field.includes("-")) {
    const [rangePart, stepPart] = field.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${field}`);
    if (start < min || end > max) throw new Error(`Range out of bounds [${min}-${max}]: ${field}`);
    if (start > end) throw new Error(`Range start must be <= end: ${field}`);

    const rangeValues = range(start, end);

    if (stepPart !== undefined) {
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step in range: ${field}`);
      return rangeValues.filter((v) => (v - start) % step === 0);
    }

    return rangeValues;
  }

  // Step with range base: n/s (shorthand for n-max/s)
  if (field.includes("/")) {
    const [baseStr, stepStr] = field.split("/");
    const base = parseInt(baseStr, 10);
    const step = parseInt(stepStr, 10);
    if (isNaN(base) || isNaN(step) || step <= 0) throw new Error(`Invalid step expression: ${field}`);
    if (base < min || base > max) throw new Error(`Value out of bounds [${min}-${max}]: ${field}`);
    return range(base, max).filter((v) => (v - base) % step === 0);
  }

  // Single number
  const num = parseInt(field, 10);
  if (isNaN(num)) throw new Error(`Invalid cron field value: ${field}`);
  if (num < min || num > max) throw new Error(`Value ${num} out of bounds [${min}-${max}]`);
  return [num];
};

const parseCron = (expression: string): CronFields => {
  if (!expression || typeof expression !== "string") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = parts;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const fieldStrings = [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr];

  return fieldNames.reduce((acc, name, i) => {
    const [min, max] = FIELD_RANGES[name];
    acc[name] = parseField(fieldStrings[i], min, max);
    return acc;
  }, {} as CronFields);
};

export default parseCron;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

