function parseField(expression: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of expression.split(",")) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) values.add(i);
      continue;
    }

    const stepMatch = trimmed.match(/^(\*|(\d+)-(\d+))\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[4], 10);
      if (step <= 0) throw new Error(`Invalid step value: ${step}`);
      const rangeMin = stepMatch[1] === "*" ? min : parseInt(stepMatch[2], 10);
      const rangeMax = stepMatch[1] === "*" ? max : parseInt(stepMatch[3], 10);
      validateRange(rangeMin, rangeMax, min, max);
      for (let i = rangeMin; i <= rangeMax; i += step) values.add(i);
      continue;
    }

    const rangeMatch = trimmed.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const start = parseInt(rangeMatch[1], 10);
      const end = parseInt(rangeMatch[2], 10);
      validateRange(start, end, min, max);
      for (let i = start; i <= end; i++) values.add(i);
      continue;
    }

    if (/^\d+$/.test(trimmed)) {
      const num = parseInt(trimmed, 10);
      if (num < min || num > max) {
        throw new Error(`Value ${num} out of range [${min}, ${max}]`);
      }
      values.add(num);
      continue;
    }

    throw new Error(`Invalid cron field expression: "${trimmed}"`);
  }

  return Array.from(values).sort((a, b) => a - b);
}

function validateRange(start: number, end: number, min: number, max: number): void {
  if (start < min || start > max) throw new Error(`Value ${start} out of range [${min}, ${max}]`);
  if (end < min || end > max) throw new Error(`Value ${end} out of range [${min}, ${max}]`);
  if (start > end) throw new Error(`Range start ${start} exceeds end ${end}`);
}

function parseCron(expression: string): CronFields {
  if (!expression || typeof expression !== "string") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  const result = {} as CronFields;
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(exprs[i], min, max);
  }

  return result;
}

export default parseCron;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: [keyof CronFields, FieldConfig][] = [
  ["minute",     { min: 0,  max: 59 }],
  ["hour",       { min: 0,  max: 23 }],
  ["dayOfMonth", { min: 1,  max: 31 }],
  ["month",      { min: 1,  max: 12 }],
  ["dayOfWeek",  { min: 0,  max: 7  }],
];

function range(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseSegment(segment: string, config: FieldConfig, fieldName: string): number[] {
  const { min, max } = config;

  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }
    if (rangePart === "*") {
      return range(min, max, step);
    }
    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new SyntaxError(`Invalid range "${rangePart}" in field "${fieldName}"`);
      }
      assertInRange(start, min, max, fieldName);
      assertInRange(end, min, max, fieldName);
      if (start > end) throw new RangeError(`Range start > end in field "${fieldName}"`);
      return range(start, end, step);
    }
    const start = parseInt(rangePart, 10);
    if (isNaN(start)) {
      throw new SyntaxError(`Invalid step expression "${segment}" in field "${fieldName}"`);
    }
    assertInRange(start, min, max, fieldName);
    return range(start, max, step);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    if (start > end) throw new RangeError(`Range start > end in field "${fieldName}"`);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(expression: string, config: FieldConfig, fieldName: string): number[] {
  const segments = expression.split(",");
  const values = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), config, fieldName)) {
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length}. Format: "minute hour dayOfMonth month dayOfWeek"`
    );
  }

  const result = {} as CronFields;
  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const [fieldName, config] = FIELD_CONFIGS[i];
    result[fieldName] = parseField(parts[i], config, fieldName);
  }
  return result;
}

