  }

  // Range: a-b
  if (expr.includes("-")) {
    const [lo, hi] = expr.split("-").map(Number);
    if (isNaN(lo) || isNaN(hi))
      throw new RangeError(`Invalid range: ${expr}`);
    validateBounds(lo, hi, config, expr);
    return rangeArray(lo, hi);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new RangeError(`Invalid value: ${expr}`);
  if (value < min || value > max)
    throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  return [value];
}

function validateBounds(
  lo: number,
  hi: number,
  config: FieldConfig,
  expr: string
): void {
  const { min, max } = config;
  if (lo < min || lo > max || hi < min || hi > max)
    throw new RangeError(
      `Value(s) in "${expr}" out of range [${min}, ${max}]`
    );
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5)
    throw new Error(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_CONFIGS) as (keyof CronExpression)[];
  const exprs  = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return Object.fromEntries(
    fields.map((field, i) => [field, parseField(exprs[i], FIELD_CONFIGS[field])])
  ) as CronExpression;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldRange = { min: number; max: number };

const FIELD_RANGES: Record<keyof CronExpression, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function rangeArray(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) result.push(i);
  return result;
}

function assertInRange(value: number, range: FieldRange, context: string): void {
  if (value < range.min || value > range.max) {
    throw new RangeError(`Value ${value} out of range [${range.min}, ${range.max}] in "${context}"`);
  }
}

function parseSegment(segment: string, range: FieldRange): number[] {
  // Step: */n or a-b/n or start/n
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const base = segment.slice(0, slashIdx);
    const step = parseInt(segment.slice(slashIdx + 1), 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in "${segment}"`);
    }

    let start: number;
    let end: number;

    if (base === "*") {
      start = range.min;
      end = range.max;
    } else if (base.includes("-")) {
      const [s, e] = base.split("-").map(Number);
      if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range in "${segment}"`);
      assertInRange(s, range, segment);
      assertInRange(e, range, segment);
      if (s > e) throw new Error(`Start exceeds end in range "${segment}"`);
      start = s;
      end = e;
    } else {
      start = parseInt(base, 10);
      if (isNaN(start)) throw new Error(`Invalid step base in "${segment}"`);
      assertInRange(start, range, segment);
      end = range.max;
    }

    return rangeArray(start, end, step);
  }

  // Wildcard
  if (segment === "*") {
    return rangeArray(range.min, range.max);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range "${segment}"`);
    assertInRange(start, range, segment);
    assertInRange(end, range, segment);
    if (start > end) throw new Error(`Start exceeds end in range "${segment}"`);
    return rangeArray(start, end);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) throw new Error(`Invalid value "${segment}"`);
  assertInRange(num, range, segment);
  return [num];
}

function parseField(field: string, range: FieldRange): number[] {
  const values = field
    .split(",")
    .flatMap((segment) => parseSegment(segment.trim(), range));

  return [...new Set(values)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(`Expected 5 cron fields, got ${parts.length}`);
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = parts;

  return {
    minute:     parseField(minuteStr, FIELD_RANGES.minute),
    hour:       parseField(hourStr,   FIELD_RANGES.hour),
    dayOfMonth: parseField(domStr,    FIELD_RANGES.dayOfMonth),
    month:      parseField(monthStr,  FIELD_RANGES.month),
    dayOfWeek:  parseField(dowStr,    FIELD_RANGES.dayOfWeek),
  };
}

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens to consume must be > 0");
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens to consume must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens capacity"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.applyRefill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const elapsed = Date.now() - this.lastRefillTime;
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs - elapsed);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

