export default RateLimiter;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 6 },   // dayOfWeek
];

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  if (field.includes(",")) {
    return field
      .split(",")
      .flatMap((part) => parseField(part.trim(), config))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (field === "*") {
    return range(min, max);
  }

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value: ${field}`);
    }
    return range(min, max).filter((v) => (v - min) % step === 0);
  }

  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value: ${field}`);
    }
    if (rangePart === "*") {
      return range(min, max).filter((v) => (v - min) % step === 0);
    }
    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new RangeError(`Invalid range in step expression: ${field}`);
      }
      if (start < min || end > max || start > end) {
        throw new RangeError(`Range out of bounds: ${field} (allowed ${min}-${max})`);
      }
      return range(start, end).filter((v) => (v - start) % step === 0);
    }
    throw new RangeError(`Unsupported step expression: ${field}`);
  }

  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new RangeError(`Invalid range: ${field}`);
    }
    if (start < min || end > max || start > end) {
      throw new RangeError(`Range out of bounds: ${field} (allowed ${min}-${max})`);
    }
    return range(start, end);
  }

  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new TypeError(`Invalid cron field value: ${field}`);
  }
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of bounds (allowed ${min}-${max})`);
  }
  return [value];
};

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new TypeError(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const [minuteConfig, hourConfig, domConfig, monthConfig, dowConfig] = FIELD_CONFIGS;

  return {
    minute: parseField(minuteField, minuteConfig),
    hour: parseField(hourField, hourConfig),
    dayOfMonth: parseField(domField, domConfig),
    month: parseField(monthField, monthConfig),
    dayOfWeek: parseField(dowField, dowConfig),
  };
}

export interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronSchedule, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function clamp(values: number[], min: number, max: number): number[] {
  return [...new Set(values.filter(v => v >= min && v <= max))].sort((a, b) => a - b);
}

function parseField(expr: string, min: number, max: number): number[] {
  const full = range(min, max);

  if (expr === "*") return full;

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${expr}`);
    return full.filter(v => (v - min) % step === 0);
  }

  if (expr.includes(",")) {
    return clamp(
      expr.split(",").flatMap(part => parseField(part.trim(), min, max)),
      min,
      max,
    );
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${expr}`);
    return clamp(range(start, end), min, max);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid cron field value: ${expr}`);
  if (value < min || value > max)
    throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  return [value];
}

export default function parseCron(expression: string): CronSchedule {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronSchedule)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  const result = {} as CronSchedule;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    let values = parseField(exprs[i], min, max);

    // Normalize dayOfWeek: treat 7 as 0 (both are Sunday)
    if (name === "dayOfWeek") {
      values = clamp(
        values.map(v => (v === 7 ? 0 : v)),
        0,
        6,
      );
    }

    result[name] = values;
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const waitMs = this.timeUntilTokens(tokens);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }

  private timeUntilTokens(tokens: number): number {
    this.refill();
    const deficit = tokens - this.currentTokens;
    if (deficit <= 0) return 0;
    const intervalsNeeded = Math.ceil(deficit / this.refillRate);
    const elapsed = Date.now() - this.lastRefillTime;
    return Math.max(0, intervalsNeeded * this.refillIntervalMs - elapsed);
  }
}

export default RateLimiter;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function dedup(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step with wildcard: */N
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step <= 0) throw new RangeError(`Step must be positive in field "${fieldName}"`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  // Step with range: N-M/S
  const stepRangeMatch = segment.match(/^(\d+)-(\d+)\/(\d+)$/);
  if (stepRangeMatch) {
    const start = parseInt(stepRangeMatch[1], 10);
    const end = parseInt(stepRangeMatch[2], 10);
    const step = parseInt(stepRangeMatch[3], 10);
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    if (start > end) throw new RangeError(`Range start > end in field "${fieldName}"`);
    if (step <= 0) throw new RangeError(`Step must be positive in field "${fieldName}"`);
    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: N-M
  const rangeMatch = segment.match(/^(\d+)-(\d+)$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end = parseInt(rangeMatch[2], 10);
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    if (start > end) throw new RangeError(`Range start > end in field "${fieldName}"`);
    return range(start, end);
  }

  // Single number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    assertInRange(value, min, max, fieldName);
    return [value];
  }

  throw new SyntaxError(`Invalid segment "${segment}" in field "${fieldName}"`);
}

function parseField(field: string, min: number, max: number, fieldName: string): number[] {
  const segments = field.split(",");
  if (segments.length === 0) throw new SyntaxError(`Empty field "${fieldName}"`);

  const values: number[] = [];
  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), min, max, fieldName);
    values.push(...parsed);
  }

  // Normalize dayOfWeek: treat 7 as 0 (both mean Sunday)
  const normalized =
    fieldName === "dayOfWeek"
      ? values.map((v) => (v === 7 ? 0 : v))
      : values;

  return dedup(normalized);
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteField,
    hourField,
    domField,
    monthField,
    dowField,
  ].map((field, i) => {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    return parseField(field, min, max, name);
  });

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(
  expr: string,
  fieldName: keyof CronFields
): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  const validateValue = (n: number): number => {
    if (!Number.isInteger(n) || n < min || n > max) {
      throw new RangeError(
        `Value ${n} out of range [${min}-${max}] for field "${fieldName}"`
      );
    }
    return n;
  };

  // Comma-separated list
  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => parseField(part.trim(), fieldName));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step value: */step or start-end/step or number/step
  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value "${stepPart}" in field "${fieldName}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((v) => parseInt(v, 10));
      start = validateValue(s);
      end = validateValue(e);
    } else {
      start = validateValue(parseInt(rangePart, 10));
      end = max;
    }

    if (start > end) {
      throw new RangeError(
        `Start ${start} is greater than end ${end} in field "${fieldName}"`
      );
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = validateValue(parseInt(startStr, 10));
    const end = validateValue(parseInt(endStr, 10));
    if (start > end) {
      throw new RangeError(
        `Start ${start} is greater than end ${end} in field "${fieldName}"`
      );
    }
    return range(start, end);
  }

  // Single number
  const num = parseInt(expr, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid value "${expr}" in field "${fieldName}"`);
  }
  return [validateValue(num)];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${parts.length}. Format: "minute hour dayOfMonth month dayOfWeek"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return fieldNames.reduce<CronFields>((acc, fieldName, index) => {
    acc[fieldName] = parseField(parts[index], fieldName);
    return acc;
  }, {} as CronFields);
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = { min: number; max: number };

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const clamp = (value: number, min: number, max: number): number =>
  Math.min(Math.max(value, min), max);

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Wildcard
  if (segment === "*") return range(min, max);

  // Step: */n or start/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: "${stepStr}"`);

    const start = base === "*" ? min : parseInt(base, 10);
    if (isNaN(start)) throw new Error(`Invalid step base: "${base}"`);

    const results: number[] = [];
    for (let i = start; i <= max; i += step) {
      if (i >= min) results.push(i);
    }
    return results;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: "${segment}"`);
    if (start > end) throw new Error(`Range start exceeds end: "${segment}"`);
    if (start < min || end > max)
      throw new Error(`Range "${segment}" out of bounds [${min}-${max}]`);
    return range(start, end);
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const values = segment.split(",").flatMap((s) => parseSegment(s.trim(), config));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value: "${segment}"`);
  if (value < min || value > max)
    throw new Error(`Value ${value} out of bounds [${min}-${max}]`);
  return [value];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;
  const keys = Object.keys(FIELD_CONFIGS) as (keyof CronExpression)[];
  const segments = [minuteStr, hourStr, domStr, monthStr, dowStr];

  return keys.reduce((acc, key, i) => {
    acc[key] = parseSegment(segments[i], FIELD_CONFIGS[key]);
    return acc;
  }, {} as CronExpression);
}

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens capacity"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

