interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const fullRange = range(min, max);

  if (field === "*") return fullRange;

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    return fullRange.filter((v) => (v - min) % step === 0);
  }

  if (field.includes(",")) {
    const parts = field.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), min, max)) values.add(v);
    }
    return [...values].sort((a, b) => a - b);
  }

  if (field.includes("-")) {
    const dashIndex = field.indexOf("-");
    const rangeStart = parseInt(field.slice(0, dashIndex), 10);
    const rest = field.slice(dashIndex + 1);

    let rangeEnd: number;
    let step = 1;

    if (rest.includes("/")) {
      const [endStr, stepStr] = rest.split("/");
      rangeEnd = parseInt(endStr, 10);
      step = parseInt(stepStr, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step in range: ${field}`);
    } else {
      rangeEnd = parseInt(rest, 10);
    }

    if (isNaN(rangeStart) || isNaN(rangeEnd)) throw new Error(`Invalid range: ${field}`);
    if (rangeStart < min || rangeEnd > max || rangeStart > rangeEnd) {
      throw new Error(`Range out of bounds [${min}-${max}]: ${field}`);
    }

    return range(rangeStart, rangeEnd).filter((v) => (v - rangeStart) % step === 0);
  }

  const num = parseInt(field, 10);
  if (isNaN(num)) throw new Error(`Invalid cron field value: ${field}`);
  if (num < min || num > max) throw new Error(`Value ${num} out of range [${min}-${max}]`);
  return [num];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const fieldValues = [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField];

  const result = {} as CronResult;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(fieldValues[i], min, max);
  }

  return result;
}

