interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronSchedule;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_NAMES: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function range(min: number, max: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseSegment(segment: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step on wildcard: */n
  const stepWildcard = segment.match(/^\*\/(\d+)$/);
  if (stepWildcard) {
    const step = parseInt(stepWildcard[1], 10);
    if (step < 1) throw new RangeError(`Step value must be >= 1 in "${segment}" for field "${field}"`);
    return range(min, max, step);
  }

  // Range with optional step: a-b or a-b/n
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const lo = parseInt(rangeMatch[1], 10);
    const hi = parseInt(rangeMatch[2], 10);
    const step = rangeMatch[3] !== undefined ? parseInt(rangeMatch[3], 10) : 1;
    assertInRange(lo, min, max, field);
    assertInRange(hi, min, max, field);
    if (lo > hi) throw new RangeError(`Range start ${lo} > end ${hi} for field "${field}"`);
    if (step < 1) throw new RangeError(`Step value must be >= 1 in "${segment}" for field "${field}"`);
    return range(lo, hi, step);
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const values = segment.split(",").flatMap(part => parseSegment(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Plain number
  const num = parseInt(segment, 10);
  if (isNaN(num)) {
    throw new SyntaxError(`Invalid cron field value "${segment}" for field "${field}"`);
  }
  assertInRange(num, min, max, field);
  return [num];
}

export function parseCron(expression: string): CronSchedule {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields but got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronSchedule;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const fieldName = FIELD_NAMES[i];
    result[fieldName] = parseSegment(fields[i], fieldName);
  }

  return result;
}

