interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0, 7],
};

function expandField(expr: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of expr.split(",")) {
    if (part === "*") {
      for (let i = min; i <= max; i++) values.add(i);
    } else if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${part}`);
      for (let i = min; i <= max; i += step) values.add(i);
    } else if (part.includes("/")) {
      const [rangePart, stepPart] = part.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${part}`);
      if (rangePart === "*") {
        for (let i = min; i <= max; i += step) values.add(i);
      } else if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map(Number);
        if (isNaN(lo) || isNaN(hi) || lo > hi) throw new Error(`Invalid range: ${rangePart}`);
        for (let i = lo; i <= hi; i += step) values.add(i);
      } else {
        const start = parseInt(rangePart, 10);
        if (isNaN(start)) throw new Error(`Invalid value: ${part}`);
        for (let i = start; i <= max; i += step) values.add(i);
      }
    } else if (part.includes("-")) {
      const [lo, hi] = part.split("-").map(Number);
      if (isNaN(lo) || isNaN(hi) || lo > hi) throw new Error(`Invalid range: ${part}`);
      for (let i = lo; i <= hi; i++) values.add(i);
    } else {
      const n = parseInt(part, 10);
      if (isNaN(n)) throw new Error(`Invalid value: ${part}`);
      values.add(n);
    }
  }

  const result = [...values].filter(v => v >= min && v <= max).sort((a, b) => a - b);
  if (result.length === 0) throw new Error(`No valid values in range [${min}, ${max}] for expression: ${expr}`);
  return result;
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}`);
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = parts;

  const rawDayOfWeek = expandField(dayOfWeekExpr, ...FIELD_RANGES.dayOfWeek);
  // Normalize Sunday: both 0 and 7 mean Sunday; map 7 → 0
  const dayOfWeek = [...new Set(rawDayOfWeek.map(v => (v === 7 ? 0 : v)))].sort((a, b) => a - b);

  return {
    minute:     expandField(minuteExpr,     ...FIELD_RANGES.minute),
    hour:       expandField(hourExpr,       ...FIELD_RANGES.hour),
    dayOfMonth: expandField(dayOfMonthExpr, ...FIELD_RANGES.dayOfMonth),
    month:      expandField(monthExpr,      ...FIELD_RANGES.month),
    dayOfWeek,
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldBounds {
  min: number;
  max: number;
}

const FIELD_BOUNDS: Record<FieldName, FieldBounds> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: FieldName[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function buildRange(from: number, to: number): number[] {
  if (from > to) throw new Error(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function clamp(value: number, min: number, max: number, context: string): number {
  if (value < min || value > max)
    throw new Error(`Value ${value} out of bounds [${min}-${max}] in "${context}"`);
  return value;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or start/n or start-end/n
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const basePart = segment.slice(0, slashIdx);
    const stepStr  = segment.slice(slashIdx + 1);
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0)
      throw new Error(`Invalid step value: "${stepStr}"`);

    let base: number[];
    if (basePart === "*") {
      base = buildRange(min, max);
    } else if (basePart.includes("-")) {
      const [s, e] = basePart.split("-").map(Number);
      clamp(s, min, max, segment);
      clamp(e, min, max, segment);
      base = buildRange(s, e);
    } else {
      const start = parseInt(basePart, 10);
      clamp(start, min, max, segment);
      base = buildRange(start, max);
    }

    return base.filter((_, i) => i % step === 0);
  }

  // Wildcard
  if (segment === "*") return buildRange(min, max);

  // Range: a-b
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) throw new Error(`Invalid range expression: "${segment}"`);
    const [s, e] = parts.map(Number);
    if (isNaN(s) || isNaN(e)) throw new Error(`Non-numeric range: "${segment}"`);
    clamp(s, min, max, segment);
    clamp(e, min, max, segment);
    return buildRange(s, e);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid token: "${segment}"`);
  clamp(value, min, max, segment);
  return [value];
}

function parseField(expr: string, bounds: FieldBounds): number[] {
  const { min, max } = bounds;

  const values = expr
    .split(",")
    .flatMap(segment => parseSegment(segment.trim(), min, max));

  const unique = [...new Set(values)].sort((a, b) => a - b);
  return unique;
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5)
    throw new Error(`Expected 5 cron fields, got ${parts.length}: "${expression}"`);

  return FIELD_ORDER.reduce((acc, name, i) => {
    acc[name] = parseField(parts[i], FIELD_BOUNDS[name]);
    return acc;
  }, {} as CronFields);
}

