  return result;
}

function parseField(expr: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Comma-separated list — recurse on each part and flatten
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap(part => parseField(part.trim(), config));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") return range(min, max);

  // Step: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1)
      throw new Error(`Invalid step value in "${expr}"`);

    if (rangePart === "*") return range(min, max, step);

    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end))
        throw new Error(`Invalid range in "${expr}"`);
      return range(start, end, step);
    }

    throw new Error(`Invalid step expression "${expr}"`);
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end))
      throw new Error(`Invalid range in "${expr}"`);
    if (start > end)
      throw new Error(`Range start ${start} exceeds end ${end} in "${expr}"`);
    return range(start, end);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value))
    throw new Error(`Invalid value "${expr}"`);
  return [value];
}

function validate(values: number[], config: FieldConfig, fieldName: string): number[] {
  for (const v of values) {
    if (v < config.min || v > config.max) {
      throw new Error(
        `Value ${v} out of range [${config.min}-${config.max}] for field "${fieldName}"`
      );
    }
  }
  return values;
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const fieldNames = Object.keys(FIELD_CONFIGS) as (keyof CronExpression)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  const result = {} as CronExpression;
  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const config = FIELD_CONFIGS[name];
    const parsed = parseField(exprs[i], config);
    result[name] = validate(parsed, config, name);
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_CONFIGS = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  },
] as const;

function range(from: number, to: number): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i++) result.push(i);
  return result;
}

function parseField(expr: string, min: number, max: number, fieldName: string): number[] {
  // Comma-separated list
  if (expr.includes(",")) {
    const values = expr.split(",").flatMap(part => parseField(part.trim(), min, max, fieldName));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (expr.includes("/")) {
    const [rangeOrStar, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in "${expr}" for field "${fieldName}"`);
    }

    let from: number;
    let to: number;

    if (rangeOrStar === "*") {
      from = min;
      to = max;
    } else if (rangeOrStar.includes("-")) {
      const [startStr, endStr] = rangeOrStar.split("-");
      from = parseInt(startStr, 10);
      to = parseInt(endStr, 10);
      if (isNaN(from) || isNaN(to)) {
        throw new Error(`Invalid range in "${expr}" for field "${fieldName}"`);
      }
    } else {
      from = parseInt(rangeOrStar, 10);
      to = max;
      if (isNaN(from)) {
        throw new Error(`Invalid start value in "${expr}" for field "${fieldName}"`);
      }
    }

    validateRange(from, to, min, max, fieldName, expr);
    const result: number[] = [];
    for (let i = from; i <= to; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const from = parseInt(startStr, 10);
    const to = parseInt(endStr, 10);
    if (isNaN(from) || isNaN(to)) {
      throw new Error(`Invalid range "${expr}" for field "${fieldName}"`);
    }
    validateRange(from, to, min, max, fieldName, expr);
    return range(from, to);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${expr}" for field "${fieldName}"`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}-${max}] for field "${fieldName}"`);
  }
  return [value];
}

function validateRange(
  from: number,
  to: number,
  min: number,
  max: number,
  fieldName: string,
  expr: string
): void {
  if (from > to) {
    throw new Error(`Range start exceeds end in "${expr}" for field "${fieldName}"`);
  }
  if (from < min || to > max) {
    throw new Error(
      `Range ${from}-${to} out of bounds [${min}-${max}] for field "${fieldName}"`
    );
  }
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  return {
    minute:     parseField(minuteExpr, FIELD_CONFIGS[0].min, FIELD_CONFIGS[0].max, "minute"),
    hour:       parseField(hourExpr,   FIELD_CONFIGS[1].min, FIELD_CONFIGS[1].max, "hour"),
    dayOfMonth: parseField(domExpr,    FIELD_CONFIGS[2].min, FIELD_CONFIGS[2].max, "dayOfMonth"),
    month:      parseField(monthExpr,  FIELD_CONFIGS[3].min, FIELD_CONFIGS[3].max, "month"),
    dayOfWeek:  parseField(dowExpr,    FIELD_CONFIGS[4].min, FIELD_CONFIGS[4].max, "dayOfWeek"),
  };
}

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens to consume must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens to wait for must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens capacity"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const elapsed = Date.now() - this.lastRefillTime;
        const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs - elapsed);

        setTimeout(attempt, waitMs);
      };

      attempt();
    });
  }
}

