export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_CONFIGS: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function buildRange(start: number, end: number): number[] {
  const out: number[] = [];
  for (let i = start; i <= end; i++) out.push(i);
  return out;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of bounds [${min}, ${max}] in "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Comma-separated list — recurse and deduplicate
  if (segment.includes(',')) {
    const merged = segment
      .split(',')
      .flatMap(part => parseSegment(part.trim(), min, max));
    return [...new Set(merged)].sort((a, b) => a - b);
  }

  // Step value: */n or start/n or start-end/n
  if (segment.includes('/')) {
    const slashIdx = segment.indexOf('/');
    const left = segment.slice(0, slashIdx);
    const stepStr = segment.slice(slashIdx + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step "${stepStr}" in "${segment}"`);
    }

    let rangeStart = min;
    let rangeEnd = max;

    if (left !== '*') {
      if (left.includes('-')) {
        const [s, e] = left.split('-').map(Number);
        assertInRange(s, min, max, segment);
        assertInRange(e, min, max, segment);
        if (s > e) throw new RangeError(`Invalid range start > end in "${segment}"`);
        rangeStart = s;
        rangeEnd = e;
      } else {
        const n = parseInt(left, 10);
        if (isNaN(n)) throw new SyntaxError(`Invalid step base "${left}" in "${segment}"`);
        assertInRange(n, min, max, segment);
        rangeStart = n;
      }
    }

    const result: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) result.push(i);
    return result;
  }

  // Wildcard
  if (segment === '*') {
    return buildRange(min, max);
  }

  // Range: start-end
  if (segment.includes('-')) {
    const [startStr, endStr] = segment.split('-');
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new SyntaxError(`Invalid range "${segment}"`);
    assertInRange(start, min, max, segment);
    assertInRange(end, min, max, segment);
    if (start > end) throw new RangeError(`Range start > end in "${segment}"`);
    return buildRange(start, end);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) throw new SyntaxError(`Unrecognized cron token "${segment}"`);
  assertInRange(num, min, max, segment);
  return [num];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Invalid cron expression: expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseSegment(minuteRaw, FIELD_CONFIGS.minute.min,     FIELD_CONFIGS.minute.max),
    hour:       parseSegment(hourRaw,   FIELD_CONFIGS.hour.min,       FIELD_CONFIGS.hour.max),
    dayOfMonth: parseSegment(domRaw,    FIELD_CONFIGS.dayOfMonth.min, FIELD_CONFIGS.dayOfMonth.max),
    month:      parseSegment(monthRaw,  FIELD_CONFIGS.month.min,      FIELD_CONFIGS.month.max),
    dayOfWeek:  parseSegment(dowRaw,    FIELD_CONFIGS.dayOfWeek.min,  FIELD_CONFIGS.dayOfWeek.max),
  };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Comma-separated list
  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => parseField(part.trim(), field));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  // Step value: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in field "${field}": ${expr}`);

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = s;
        end = e;
      } else {
        start = parseInt(rangePart, 10);
      }
    }

    if (start < min || end > max) {
      throw new Error(`Value out of range for field "${field}": ${expr} (valid: ${min}-${max})`);
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in field "${field}": ${expr}`);
    if (start < min || end > max || start > end) {
      throw new Error(`Range out of bounds for field "${field}": ${expr} (valid: ${min}-${max})`);
    }
    return range(start, end);
  }

  // Single number
  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new Error(`Invalid value in field "${field}": ${expr}`);
  if (num < min || num > max) {
    throw new Error(`Value ${num} out of range for field "${field}" (valid: ${min}-${max})`);
  }
  return [num];
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Invalid cron expression: expected 5 fields, got ${parts.length}`);
  }

  const fields: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  const result = {} as CronResult;
  for (let i = 0; i < fields.length; i++) {
    result[fields[i]] = parseField(parts[i], fields[i]);
  }

  return result;
}

