export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`tokens (${tokens}) exceeds maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const waitMs = intervalsNeeded * this.refillIntervalMs;
      const elapsed = Date.now() - this.lastRefillTime;
      const remaining = Math.max(0, waitMs - (elapsed % this.refillIntervalMs));
      await new Promise<void>((resolve) => setTimeout(resolve, remaining || this.refillIntervalMs));
    }
  }
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = { min: number; max: number };

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(expr: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Comma-separated list
  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), config))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step value: */step or start-end/step
  if (expr.includes("/")) {
    const [rangepart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value: ${stepStr}`);
    }

    let start: number;
    let end: number;

    if (rangepart === "*") {
      start = min;
      end = max;
    } else if (rangepart.includes("-")) {
      const [s, e] = rangepart.split("-").map((n) => parseInt(n, 10));
      start = clamp(s, min, max);
      end = clamp(e, min, max);
    } else {
      start = clamp(parseInt(rangepart, 10), min, max);
      end = max;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) {
      throw new RangeError(`Invalid range: ${expr} (start > end)`);
    }
    return range(start, end);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid cron field value: ${expr}`);
  }
  return [clamp(value, min, max)];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const keys = Object.keys(FIELD_CONFIGS) as (keyof CronExpression)[];
  const result = {} as CronExpression;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    result[key] = parseField(fields[i], FIELD_CONFIGS[key]);
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   7],
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function expandField(expr: string, min: number, max: number): number[] {
  // Comma-separated list
  if (expr.includes(",")) {
    return [...new Set(
      expr.split(",").flatMap(part => expandField(part.trim(), min, max))
    )].sort((a, b) => a - b);
  }

  // Wildcard with optional step: * or */n
  if (expr.startsWith("*")) {
    const stepPart = expr.slice(1);
    const step = stepPart.startsWith("/") ? parseInt(stepPart.slice(1), 10) : 1;
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step value in "${expr}"`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  // Range with optional step: a-b or a-b/n
  if (expr.includes("-")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = stepStr !== undefined ? parseInt(stepStr, 10) : 1;
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step in "${expr}"`);
    const [startStr, endStr] = rangePart.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end   = clamp(parseInt(endStr,   10), min, max);
    if (start > end) throw new RangeError(`Invalid range "${expr}": start > end`);
    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new SyntaxError(`Unexpected token "${expr}"`);
  return [clamp(value, min, max)];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${parts.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = expandField(parts[i], min, max);
  }

  return result;
}

