function assertInRange(values: number[], min: number, max: number, field: string): void {
  for (const v of values) {
    if (v < min || v > max) {
      throw new RangeError(`Value ${v} out of range [${min}, ${max}] for field "${field}"`);
    }
  }
}

function parseSegment(segment: string, min: number, max: number, field: string): number[] {
  // Wildcard: *
  if (segment === "*") return expand(min, max);

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step "${stepStr}" in field "${field}"`);

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map(Number);
        if (isNaN(lo) || isNaN(hi)) throw new SyntaxError(`Invalid range "${rangePart}" in field "${field}"`);
        rangeMin = lo;
        rangeMax = hi;
      } else {
        rangeMin = parseInt(rangePart, 10);
        if (isNaN(rangeMin)) throw new SyntaxError(`Invalid value "${rangePart}" in field "${field}"`);
        rangeMax = max;
      }
    }

    assertInRange([rangeMin, rangeMax], min, max, field);
    return expand(rangeMin, rangeMax, step);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [loStr, hiStr] = segment.split("-");
    const lo = parseInt(loStr, 10);
    const hi = parseInt(hiStr, 10);
    if (isNaN(lo) || isNaN(hi)) throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    assertInRange([lo, hi], min, max, field);
    if (lo > hi) throw new RangeError(`Range start ${lo} > end ${hi} in field "${field}"`);
    return expand(lo, hi);
  }

  // Single number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  assertInRange([n], min, max, field);
  return [n];
}

function parseField(expr: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  const parts = expr.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    for (const v of parseSegment(part.trim(), min, max, field)) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
}

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens"));

    return new Promise<void>((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function rangeArray(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  if (field === "*") {
    return rangeArray(min, max);
  }

  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    const [rangeStart, rangeEnd] = rangePart.includes("-")
      ? rangePart.split("-").map((n) => parseInt(n, 10))
      : [parseInt(rangePart, 10), max];
    if (isNaN(rangeStart) || isNaN(rangeEnd)) throw new Error(`Invalid range in: ${field}`);
    validateRange(rangeStart, rangeEnd, min, max, field);
    const result: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) result.push(i);
    return result;
  }

  if (field.includes("-")) {
    const parts = field.split("-");
    if (parts.length !== 2) throw new Error(`Invalid range: ${field}`);
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range values: ${field}`);
    validateRange(start, end, min, max, field);
    return rangeArray(start, end);
  }

  const value = parseInt(field, 10);
  if (isNaN(value)) throw new Error(`Invalid cron field value: ${field}`);
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in field: ${field}`);
  }
  return [value];
}

function validateRange(start: number, end: number, min: number, max: number, field: string): void {
  if (start < min || end > max || start > end) {
    throw new Error(`Range ${start}-${end} is invalid for bounds [${min}, ${max}] in: ${field}`);
  }
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const fieldValues = [minuteField, hourField, domField, monthField, dowField];

  const result = {} as CronResult;
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(fieldValues[i], min, max);
  }

  return result;
}

export default parseCron;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronExpression, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function expandRange(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

function parseField(field: string, rangeMin: number, rangeMax: number): number[] {
  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), rangeMin, rangeMax));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") {
    return expandRange(rangeMin, rangeMax);
  }

  // Step value: */n or start-end/n
  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepPart}`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = rangeMin;
      end = rangeMax;
    } else if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map((n) => parseInt(n, 10));
      if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range in step: ${rangePart}`);
      start = clamp(lo, rangeMin, rangeMax);
      end = clamp(hi, rangeMin, rangeMax);
    } else {
      const n = parseInt(rangePart, 10);
      if (isNaN(n)) throw new Error(`Invalid step base: ${rangePart}`);
      start = clamp(n, rangeMin, rangeMax);
      end = rangeMax;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (field.includes("-")) {
    const [lo, hi] = field.split("-").map((n) => parseInt(n, 10));
    if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range: ${field}`);
    const start = clamp(lo, rangeMin, rangeMax);
    const end = clamp(hi, rangeMin, rangeMax);
    if (start > end) throw new Error(`Invalid range (start > end): ${field}`);
    return expandRange(start, end);
  }

  // Single number
  const n = parseInt(field, 10);
  if (isNaN(n)) throw new Error(`Invalid cron field value: ${field}`);
  if (n < rangeMin || n > rangeMax) {
    throw new Error(`Value ${n} out of range [${rangeMin}, ${rangeMax}]`);
  }
  return [n];
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 cron fields, got ${parts.length}: "${expression}"`);
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronExpression)[];
  const result = {} as CronExpression;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(parts[i], min, max);
  }

  // Normalize dayOfWeek: treat 7 as equivalent to 0 (both = Sunday)
  if (result.dayOfWeek.includes(7) && !result.dayOfWeek.includes(0)) {
    result.dayOfWeek = [0, ...result.dayOfWeek.filter((d) => d !== 7)].sort((a, b) => a - b);
  } else if (result.dayOfWeek.includes(7)) {
    result.dayOfWeek = result.dayOfWeek.filter((d) => d !== 7);
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: Array<keyof CronFields> = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const range = (start: number, end: number, step = 1): number[] => {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) result.push(i);
  return result;
};

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
};

const parseSegment = (segment: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  // Wildcard: *
  if (segment === "*") return range(min, max);

  // Step: */n or start/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: "${stepStr}"`);

    if (base === "*") return range(min, max, step);

    // Range with step: start-end/n
    if (base.includes("-")) {
      const [startStr, endStr] = base.split("-");
      const start = clamp(parseInt(startStr, 10), min, max);
      const end   = clamp(parseInt(endStr,   10), min, max);
      if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
      return range(start, end, step);
    }

    const start = clamp(parseInt(base, 10), min, max);
    return range(start, max, step);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end   = clamp(parseInt(endStr,   10), min, max);
    if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid cron token: "${segment}"`);
  return [clamp(value, min, max)];
};

const parseField = (expression: string, config: FieldConfig): number[] => {
  // Comma-separated list
  const parts = expression.split(",");
  const values = parts.flatMap((part) => parseSegment(part.trim(), config));
  return [...new Set(values)].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronFields => {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 cron fields, got ${parts.length}: "${expression}"`
    );
  }

  return Object.fromEntries(
    FIELD_ORDER.map((field, i) => [
      field,
      parseField(parts[i], FIELD_CONFIGS[field]),
    ])
  ) as CronFields;
};

export default parseCron;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES = {
  minute:     [0,  59] as const,
  hour:       [0,  23] as const,
  dayOfMonth: [1,  31] as const,
  month:      [1,  12] as const,
  dayOfWeek:  [0,   7] as const, // 0 and 7 both represent Sunday
};

function expandToken(token: string, min: number, max: number): number[] {
  // Comma-separated list — recurse on each part, deduplicate, sort
  if (token.includes(",")) {
    const values = token
      .split(",")
      .flatMap((t) => expandToken(t.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step expression: */n  or  start-end/n  or  start/n
  if (token.includes("/")) {
    const slashIdx = token.lastIndexOf("/");
    const rangePart = token.slice(0, slashIdx);
    const step = parseInt(token.slice(slashIdx + 1), 10);

    if (isNaN(step) || step < 1) {
      throw new RangeError(`Invalid step in "${token}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        [rangeMin, rangeMax] = parseRange(rangePart, min, max);
      } else {
        rangeMin = parseNumber(rangePart, min, max);
        rangeMax = max;
      }
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (token.includes("-")) {
    const [lo, hi] = parseRange(token, min, max);
    return Array.from({ length: hi - lo + 1 }, (_, i) => lo + i);
  }

  // Wildcard
  if (token === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Single number
  return [parseNumber(token, min, max)];
}

function parseNumber(token: string, min: number, max: number): number {
  const n = parseInt(token, 10);
  if (isNaN(n) || String(n) !== token.trim()) {
    throw new TypeError(`"${token}" is not a valid integer`);
  }
  if (n < min || n > max) {
    throw new RangeError(`Value ${n} is outside allowed range [${min}, ${max}]`);
  }
  return n;
}

function parseRange(
  token: string,
  min: number,
  max: number
): [number, number] {
  const parts = token.split("-");
  if (parts.length !== 2) {
    throw new TypeError(`Invalid range "${token}"`);
  }
  const lo = parseNumber(parts[0], min, max);
  const hi = parseNumber(parts[1], min, max);
  if (lo > hi) {
    throw new RangeError(`Range start ${lo} exceeds end ${hi} in "${token}"`);
  }
  return [lo, hi];
}

export default function parseCron(expression: string): CronExpression {
  const tokens = expression.trim().split(/\s+/);

  if (tokens.length !== 5) {
    throw new TypeError(
      `Expected 5 cron fields, received ${tokens.length}: "${expression}"`
    );
  }

  const [minuteTok, hourTok, domTok, monthTok, dowTok] = tokens;

  return {
    minute:     expandToken(minuteTok, ...FIELD_RANGES.minute),
    hour:       expandToken(hourTok,   ...FIELD_RANGES.hour),
    dayOfMonth: expandToken(domTok,    ...FIELD_RANGES.dayOfMonth),
    month:      expandToken(monthTok,  ...FIELD_RANGES.month),
    dayOfWeek:  expandToken(dowTok,    ...FIELD_RANGES.dayOfWeek),
  };
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_RANGES: Record<FieldName, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function buildRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function assertInRange(value: number, min: number, max: number, context: string): number {
  if (isNaN(value) || value < min || value > max) {
    throw new RangeError(`Value ${value} out of valid range [${min}, ${max}] in "${context}"`);
  }
  return value;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Comma-separated list — recurse on each part
  if (segment.includes(",")) {
    const values = segment
      .split(",")
      .flatMap((part) => parseSegment(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step value: */n  |  start/n  |  start-end/n
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const rangePart = segment.slice(0, slashIdx);
    const step = parseInt(segment.slice(slashIdx + 1), 10);

    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value in "${segment}"`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (rangePart === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((n) => parseInt(n, 10));
      rangeStart = assertInRange(s, min, max, segment);
      rangeEnd   = assertInRange(e, min, max, segment);
    } else {
      rangeStart = assertInRange(parseInt(rangePart, 10), min, max, segment);
      rangeEnd   = max;
    }

    if (rangeStart > rangeEnd) {
      throw new RangeError(`Range start exceeds end in "${segment}"`);
    }

    const result: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) result.push(i);
    return result;
  }

  // Wildcard
  if (segment === "*") {
    return buildRange(min, max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const start = assertInRange(parseInt(segment.slice(0, dashIdx), 10), min, max, segment);
    const end   = assertInRange(parseInt(segment.slice(dashIdx + 1), 10), min, max, segment);
    if (start > end) throw new RangeError(`Range start exceeds end in "${segment}"`);
    return buildRange(start, end);
  }

  // Single integer
  const value = parseInt(segment, 10);
  return [assertInRange(value, min, max, segment)];
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Invalid cron expression: expected 5 fields, got ${parts.length} — "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = parts;
  const r = FIELD_RANGES;

  return {
    minute:     parseSegment(minuteRaw, ...r.minute),
    hour:       parseSegment(hourRaw,   ...r.hour),
    dayOfMonth: parseSegment(domRaw,    ...r.dayOfMonth),
    month:      parseSegment(monthRaw,  ...r.month),
    dayOfWeek:  parseSegment(dowRaw,    ...r.dayOfWeek),
  };
}

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const deficit = tokens - this.tokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const timeUntilRefill = this.refillIntervalMs - (Date.now() - this.lastRefillTime);
      const waitMs = Math.max(0, timeUntilRefill + (intervalsNeeded - 1) * this.refillIntervalMs);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be greater than 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be greater than 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be greater than 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed >= this.refillIntervalMs) {
      const intervals = Math.floor(elapsed / this.refillIntervalMs);
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be greater than 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be greater than 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens capacity"));

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const tokensNeeded = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
        const elapsed = Date.now() - this.lastRefillTime;
        const msUntilNextInterval = this.refillIntervalMs - elapsed;
        const delayMs = Math.max(0, msUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs);

        setTimeout(attempt, delayMs);
      };

      attempt();
    });
  }
}

export default RateLimiter;
